import { stripeBillingErrorResponse } from "@/lib/stripe/http";
import { createAdminClient } from "@/lib/supabase/admin";
import { createClient } from "@/lib/supabase/server";

export async function POST() {
  let config: ReturnType<typeof getStripeConfig>;
  try {
    config = getStripeConfig();
  } catch (error) {
    const response = stripeBillingErrorResponse(error);
    if (response) {
      return response;
    }
    throw error;
  }

  const supabase = await createClient();
  const { data: userData, error: userError } = await supabase.auth.getUser();
  if (userError || !userData.user) {
    return NextResponse.json({ error: "Authentication required." }, { status: 401 });
  }

  const adminClient = createAdminClient();
  const { data: billingCustomer } = await adminClient
    .from("billing_customers")
    .select("stripe_customer_id")
    .eq("user_id", userData.user.id)
    .maybeSingle();

  let stripeCustomerId = billingCustomer?.stripe_customer_id;
  if (!stripeCustomerId) {
    const { data: subscription } = await adminClient
      .from("subscriptions")
      .select("stripe_customer_id")
      .eq("user_id", userData.user.id)
      .limit(1)
      .maybeSingle();
    stripeCustomerId = subscription?.stripe_customer_id;
  }

  if (!stripeCustomerId) {
    return NextResponse.json(
      {
        error: "No billing account found for this user yet. Start a checkout first.",
        code: "billing_customer_not_found",
      },
      { status: 404 },
    );
  }

  const stripe = getStripe();
  const session = await stripe.billingPortal.sessions.create({
    customer: stripeCustomerId,
    return_url: `${config.appUrl}/settings/billing`,
  });

  return NextResponse.json({ url: session.url });
}

