import { NextResponse } from "next/server";
import type Stripe from "stripe";
import { getStripe } from "@/lib/stripe/client";
import { getStripeWebhookConfig } from "@/lib/stripe/env";
import { stripeBillingErrorResponse } from "@/lib/stripe/http";
import { handleEvent } from "@/lib/stripe/webhooks";

export async function POST(request: Request) {
  let config: ReturnType<typeof getStripeWebhookConfig>;
  try {
    config = getStripeWebhookConfig();
  } catch (error) {
    const response = stripeBillingErrorResponse(error);
    if (response) {
      return response;
    }
    throw error;
  }

  const signature = request.headers.get("stripe-signature");
  if (!signature) {
    return NextResponse.json({ error: "Missing Stripe signature header." }, { status: 400 });
  }

  const payload = await request.text();
  const stripe = getStripe(config.secretKey);

  let event: Stripe.Event;
  try {
    event = stripe.webhooks.constructEvent(payload, signature, config.webhookSecret);
  } catch (error) {
    const message = error instanceof Error ? error.message : "Invalid Stripe webhook signature.";
    return NextResponse.json({ error: message }, { status: 400 });
  }

  try {
    await handleEvent(event, stripe);
  } catch (error) {
    console.error("Stripe webhook handling failed", error);
    return NextResponse.json({ error: "Failed to process webhook event." }, { status: 500 });
  }

  return NextResponse.json({ received: true });
}

